export function init(container, dotnetRef, timeoutMs) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) clearTimeout(timerId);
        if (isIdle) {
            isIdle = false;
            dotnetRef.invokeMethodAsync("OnActiveTriggered");
        }
        timerId = setTimeout(() => {
            isIdle = true;
            dotnetRef.invokeMethodAsync("OnIdleTriggered");
        }, timeoutMs);
    }

    events.forEach(e => container.addEventListener(e, resetTimer, { passive: true }));

    // Start the initial timer
    resetTimer();

    state = { container, events, resetTimer, timerId: () => timerId, clearTimer: () => { if (timerId !== null) clearTimeout(timerId); timerId = null; } };
}

export function dispose() {
    if (!state) return;
    state.clearTimer();
    state.events.forEach(e => state.container.removeEventListener(e, state.resetTimer));
    state = null;
}

